
use super::*;
use crate::TerminalSettings;
use alacritty_terminal::{
    event::VoidListener,
    grid::Scroll,
    index::{Column, Point as AlacPoint},
    term::{Term, test::mock_term},
};
use settings::{self, Settings, SettingsContent};
use std::{cell::RefCell, rc::Rc};
use util_macros::perf;

fn build_test_term(
    line: &str,
    repeat: usize,
    hover_offset_column: usize,
) -> (Term<VoidListener>, AlacPoint) {
    let content = line.repeat(repeat);
    let mut term = mock_term(&content);
    term.resize(TermSize {
        columns: 1024,
        screen_lines: 10,
    });
    term.scroll_display(Scroll::Top);
    let point = AlacPoint::new(Line(term.topmost_line().0 + 3), Column(hover_offset_column));
    (term, point)
}

#[perf]
pub fn cargo_hyperlink_benchmark() {
    const LINE: &str = "    Compiling terminal v0.1.0 (/Hyperlinks/Bench/Source/mav-hyperlinks/crates/terminal)\r\n";
    thread_local! {
        static TEST_TERM_AND_POINT: (Term<VoidListener>, AlacPoint) =
            build_test_term(LINE, 500, 50);
    }
    TEST_TERM_AND_POINT.with(|(term, point)| {
        assert_eq!(
            find_from_grid_point_bench(term, *point)
                .map(|hyperlink| hyperlink.text)
                .unwrap_or_default(),
            "/Hyperlinks/Bench/Source/mav-hyperlinks/crates/terminal",
            "Hyperlink should have been found"
        );
    });
}

